{"code": "import json
import re
from collections import defaultdict

# Access the stored results directly
reviews_list = var_functions.query_db:6
books_list = var_functions.query_db:9

# Process reviews data
reviews = []
for review in reviews_list:
    if 'purchase_id' in review and 'rating' in review:
        try:
            rating = float(review['rating'])
            purchase_id = review['purchase_id']
            if purchase_id and rating > 0:
                reviews.append({'purchase_id': purchase_id, 'rating': rating})
        except (ValueError, TypeError):
            continue

# Process books data and extract publication years
books = {}
year_pattern = r'(\d{4})'

for book in books_list:
    if 'book_id' in book and 'details' in book:
        book_id = book['book_id']
        details = book['details']

        year_match = re.search(year_pattern, details)
        if year_match:
            try:
                year = int(year_match.group(1))
                if 1800 <= year <= 2025:
                    decade = (year // 10) * 10
                    books[book_id] = {'decade': f"{decade}s"}
            except (ValueError, TypeError):
                continue

# Group ratings by book (mapping purchase_id to book_id)
book_ratings = defaultdict(list)

for review in reviews:
    purchase_id = review['purchase_id']
    if purchase_id.startswith('purchaseid_'):
        book_num = purchase_id.replace('purchaseid_', '')
        book_id = f'bookid_{book_num}'

        if book_id in books:
            book_ratings[book_id].append(review['rating'])

# Calculate average rating per book and group by decade
decade_ratings = defaultdict(lambda: {'total': 0, 'count': 0, 'books': []})

for book_id, ratings in book_ratings.items():
    if book_id in books and ratings:
        avg_rating = sum(ratings) / len(ratings)
        decade = books[book_id]['decade']
        decade_ratings[decade]['total'] += avg_rating
        decade_ratings[decade]['count'] += 1
        decade_ratings[decade]['books'].append(book_id)

# Filter for decades with at least 10 books and find highest average
eligible = []
for decade, stats in decade_ratings.items():
    if stats['count'] >= 10:
        avg = stats['total'] / stats['count']
        eligible.append((decade, round(avg, 3), stats['count']))

eligible.sort(key=lambda x: x[1], reverse=True)

result = {
    'top_decade': eligible[0][0] if eligible else None,
    'top_rating': eligible[0][1] if eligible else None,
    'total_eligible_decades': len(eligible)
}

print('__RESULT__:')
print(json.dumps(result))"}

